package am.froshy.mialu.launcher;

import am.froshy.mialu.launcher.api.internal.InternalApiServer;
import am.froshy.mialu.launcher.application.LauncherService;
import am.froshy.mialu.launcher.application.LauncherUpdateService;
import am.froshy.mialu.launcher.config.LauncherConfig;
import am.froshy.mialu.launcher.infrastructure.ProfileStore;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.net.URI;

public final class LauncherRuntime {
    private final LauncherConfig config;
    private final InternalApiServer apiServer;

    private LauncherRuntime(LauncherConfig config, InternalApiServer apiServer) {
        this.config = config;
        this.apiServer = apiServer;
    }

    public static LauncherRuntime start() {
        LauncherConfig config = LauncherConfig.fromEnvironment();
        ObjectMapper objectMapper = new ObjectMapper().findAndRegisterModules();

        LauncherService launcherService = new LauncherService(config, new ProfileStore(config.profilesFile(), objectMapper));
        LauncherUpdateService updateService = new LauncherUpdateService(config.launcherVersion(), config.updatesMetadataUrl());
        InternalApiServer apiServer = new InternalApiServer(config.internalApiPort(), launcherService, updateService);
        apiServer.start();

        return new LauncherRuntime(config, apiServer);
    }

    public URI apiBaseUri() {
        return URI.create("http://localhost:" + apiServer.getPort() + "/internal/v1");
    }

    public int apiPort() {
        return apiServer.getPort();
    }

    public LauncherConfig config() {
        return config;
    }

    public void stop() {
        apiServer.stop();
    }
}

package am.froshy.mialu.launcher;

import am.froshy.mialu.launcher.api.internal.InternalApiServer;
import am.froshy.mialu.launcher.application.LauncherService;
import am.froshy.mialu.launcher.application.LauncherUpdateService;
import am.froshy.mialu.launcher.config.LauncherConfig;
import am.froshy.mialu.launcher.infrastructure.ProfileStore;
import am.froshy.mialu.launcher.infrastructure.SettingsStore;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.net.URI;

public final class LauncherRuntime {
    private final LauncherConfig config;
    private final InternalApiServer apiServer;

    private LauncherRuntime(LauncherConfig config, InternalApiServer apiServer) {
        this.config = config;
        this.apiServer = apiServer;
    }

    public static LauncherRuntime start() {
        LauncherConfig config = LauncherConfig.fromEnvironment();
        ObjectMapper objectMapper = new ObjectMapper().findAndRegisterModules();

        LauncherService launcherService = new LauncherService(config, new ProfileStore(config.profilesFile(), objectMapper));
        SettingsStore settingsStore = new SettingsStore(config.baseDirectory().resolve("settings.json"), objectMapper);
        LauncherUpdateService updateService = new LauncherUpdateService(
                config.launcherVersion(),
                config.updatesMetadataUrl(),
                config.baseDirectory().resolve("updates"),
                settingsStore
        );
        InternalApiServer apiServer = new InternalApiServer(config.internalApiPort(), launcherService, updateService);
        apiServer.start();

        return new LauncherRuntime(config, apiServer);
    }

    public URI apiBaseUri() {
        return URI.create("http://localhost:" + apiServer.getPort() + "/internal/v1");
    }

    public int apiPort() {
        return apiServer.getPort();
    }

    public LauncherConfig config() {
        return config;
    }

    public void stop() {
        apiServer.stop();
    }
}

package am.froshy.mialu.launcher.api.internal;

import am.froshy.mialu.launcher.domain.DownloadStatus;
import am.froshy.mialu.launcher.domain.LaunchRequest;
import am.froshy.mialu.launcher.domain.LaunchResult;
import am.froshy.mialu.launcher.domain.LauncherUpdateStatus;
import am.froshy.mialu.launcher.domain.MinecraftProfile;
import am.froshy.mialu.launcher.domain.PreparedLaunchStatus;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.List;
import java.util.Map;

public final class InternalApiClient {
    private final URI baseUri;
    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;

    public InternalApiClient(URI baseUri) {
        String normalizedBase = baseUri.toString().endsWith("/") ? baseUri.toString() : baseUri + "/";
        this.baseUri = URI.create(normalizedBase);
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(3))
                .build();
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
    }

    public Map<String, Object> health() {
        return send("health", "GET", null, new TypeReference<>() {});
    }

    public List<MinecraftProfile> listProfiles() {
        return send("profiles", "GET", null, new TypeReference<>() {});
    }

    public MinecraftProfile createProfile(MinecraftProfile profile) {
        return send("profiles", "POST", profile, new TypeReference<>() {});
    }

    public MinecraftProfile updateProfile(String existingId, MinecraftProfile profile) {
        return send("profiles/" + existingId, "PUT", profile, new TypeReference<>() {});
    }

    public void deleteProfile(String profileId) {
        send("profiles/" + profileId, "DELETE", null, new TypeReference<Map<String, Object>>() {});
    }

    public String getProfileInstancePath(String profileId) {
        Map<String, Object> response = send("profiles/" + profileId + "/instance-path", "GET", null, new TypeReference<>() {});
        Object instancePath = response.get("instancePath");
        return instancePath == null ? "" : instancePath.toString();
    }

    public LaunchResult launch(LaunchRequest request) {
        return send("launch", "POST", request, new TypeReference<>() {});
    }

    public LaunchResult launchPrepared(LaunchRequest request) {
        return send("launch-prepared", "POST", request, new TypeReference<>() {});
    }

    public PreparedLaunchStatus startLaunchPreparedAsync(LaunchRequest request) {
        return send("launch-prepared/start", "POST", request, new TypeReference<>() {});
    }

    public PreparedLaunchStatus getLaunchPreparedStatus(String operationId) {
        return send("launch-prepared/" + operationId, "GET", null, new TypeReference<>() {});
    }

    public DownloadStatus startDownload(String target) {
        return send("downloads", "POST", Map.of("target", target), new TypeReference<>() {});
    }

    public DownloadStatus getDownloadStatus(String downloadId) {
        return send("downloads/" + downloadId, "GET", null, new TypeReference<>() {});
    }

    public LauncherUpdateStatus checkUpdates() {
        return send("updates/check", "GET", null, new TypeReference<>() {});
    }

    public DownloadStatus prepareVersion(String version) {
        return send("versions/prepare", "POST", Map.of("version", version), new TypeReference<>() {});
    }

    public String getModpackCompatibilityMode() {
        Map<String, Object> response = send("settings/modpack-compat", "GET", null, new TypeReference<>() {});
        Object mode = response.get("mode");
        return mode == null ? "BOTH" : mode.toString();
    }

    public String setModpackCompatibilityMode(String mode) {
        Map<String, Object> response = send("settings/modpack-compat", "POST", Map.of("mode", mode), new TypeReference<>() {});
        Object applied = response.get("mode");
        return applied == null ? "BOTH" : applied.toString();
    }

    public Map<String, Object> getGameOutput(String launchId, int fromIndex) {
        return send("launch/" + launchId + "/output?from=" + fromIndex, "GET", null, new TypeReference<>() {});
    }

    public boolean isGameAlive(String launchId) {
        Map<String, Object> res = send("launch/" + launchId + "/alive", "GET", null, new TypeReference<>() {});
        return Boolean.TRUE.equals(res.get("alive"));
    }

    private <T> T send(String path, String method, Object body, TypeReference<T> typeReference) {
        try {
            HttpRequest request = buildRequest(path, method, body);
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() >= 400) {
                throw new IllegalStateException("Error API " + response.statusCode() + ": " + response.body());
            }
            return objectMapper.readValue(response.body(), typeReference);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo parsear la respuesta", ex);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new IllegalStateException("Llamada interrumpida", ex);
        }
    }

    private HttpRequest buildRequest(String path, String method, Object body) throws IOException {
        HttpRequest.Builder builder = HttpRequest.newBuilder()
                .uri(baseUri.resolve(path))
                .timeout(Duration.ofSeconds(10))
                .header("Content-Type", "application/json");

        if ("GET".equalsIgnoreCase(method)) {
            return builder.GET().build();
        }

        byte[] payload = objectMapper.writeValueAsBytes(body);
        return builder.method(method, HttpRequest.BodyPublishers.ofByteArray(payload)).build();
    }
}

package am.froshy.mialu.launcher.api.internal;

import am.froshy.mialu.launcher.domain.DownloadStatus;
import am.froshy.mialu.launcher.domain.LaunchRequest;
import am.froshy.mialu.launcher.domain.LaunchResult;
import am.froshy.mialu.launcher.domain.LauncherUpdateStatus;
import am.froshy.mialu.launcher.domain.MinecraftProfile;
import am.froshy.mialu.launcher.domain.PreparedLaunchStatus;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.IOException;
import java.net.URI;
import java.net.URLEncoder;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.time.Duration;
import java.util.List;
import java.util.Map;

public final class InternalApiClient {
    private final URI baseUri;
    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;

    public InternalApiClient(URI baseUri) {
        String normalizedBase = baseUri.toString().endsWith("/") ? baseUri.toString() : baseUri + "/";
        this.baseUri = URI.create(normalizedBase);
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(3))
                .build();
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
    }

    public Map<String, Object> health() {
        return send("health", "GET", null, new TypeReference<>() {});
    }

    public List<MinecraftProfile> listProfiles() {
        return send("profiles", "GET", null, new TypeReference<>() {});
    }

    public MinecraftProfile createProfile(MinecraftProfile profile) {
        return send("profiles", "POST", profile, new TypeReference<>() {});
    }

    public MinecraftProfile updateProfile(String existingId, MinecraftProfile profile) {
        return send("profiles/" + encodePathSegment(existingId), "PUT", profile, new TypeReference<>() {});
    }

    public void deleteProfile(String profileId) {
        send("profiles/" + encodePathSegment(profileId), "DELETE", null, new TypeReference<Map<String, Object>>() {});
    }

    public String getProfileInstancePath(String profileId) {
        Map<String, Object> response = send("profiles/" + encodePathSegment(profileId) + "/instance-path", "GET", null, new TypeReference<>() {});
        Object instancePath = response.get("instancePath");
        return instancePath == null ? "" : instancePath.toString();
    }

    public LaunchResult launch(LaunchRequest request) {
        return send("launch", "POST", request, new TypeReference<>() {});
    }

    public LaunchResult launchPrepared(LaunchRequest request) {
        return send("launch-prepared", "POST", request, new TypeReference<>() {});
    }

    public PreparedLaunchStatus startLaunchPreparedAsync(LaunchRequest request) {
        return send("launch-prepared/start", "POST", request, new TypeReference<>() {});
    }

    public PreparedLaunchStatus getLaunchPreparedStatus(String operationId) {
        return send("launch-prepared/" + encodePathSegment(operationId), "GET", null, new TypeReference<>() {});
    }

    public DownloadStatus startDownload(String target) {
        return send("downloads", "POST", Map.of("target", target), new TypeReference<>() {});
    }

    public DownloadStatus getDownloadStatus(String downloadId) {
        return send("downloads/" + encodePathSegment(downloadId), "GET", null, new TypeReference<>() {});
    }

    public LauncherUpdateStatus checkUpdates() {
        return checkUpdatesManual();
    }

    public LauncherUpdateStatus checkUpdatesManual() {
        return send("updates/check?trigger=MANUAL", "GET", null, new TypeReference<>() {});
    }

    public LauncherUpdateStatus checkUpdatesWeekly() {
        return send("updates/check?trigger=WEEKLY", "GET", null, new TypeReference<>() {});
    }

    public DownloadStatus prepareVersion(String version) {
        return send("versions/prepare", "POST", Map.of("version", version), new TypeReference<>() {});
    }

    public String getModpackCompatibilityMode() {
        Map<String, Object> response = send("settings/modpack-compat", "GET", null, new TypeReference<>() {});
        Object mode = response.get("mode");
        return mode == null ? "BOTH" : mode.toString();
    }

    public String setModpackCompatibilityMode(String mode) {
        Map<String, Object> response = send("settings/modpack-compat", "POST", Map.of("mode", mode), new TypeReference<>() {});
        Object applied = response.get("mode");
        return applied == null ? "BOTH" : applied.toString();
    }

    public Map<String, Object> getGameOutput(String launchId, int fromIndex) {
        return send("launch/" + encodePathSegment(launchId) + "/output?from=" + fromIndex, "GET", null, new TypeReference<>() {});
    }

    public boolean isGameAlive(String launchId) {
        Map<String, Object> res = send("launch/" + encodePathSegment(launchId) + "/alive", "GET", null, new TypeReference<>() {});
        return Boolean.TRUE.equals(res.get("alive"));
    }

    private <T> T send(String path, String method, Object body, TypeReference<T> typeReference) {
        try {
            HttpRequest request = buildRequest(path, method, body);
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() >= 400) {
                throw new IllegalStateException("Error API " + response.statusCode() + ": " + response.body());
            }
            return objectMapper.readValue(response.body(), typeReference);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo parsear la respuesta", ex);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new IllegalStateException("Llamada interrumpida", ex);
        }
    }

    private HttpRequest buildRequest(String path, String method, Object body) throws IOException {
        HttpRequest.Builder builder = HttpRequest.newBuilder()
                .uri(baseUri.resolve(path))
                .timeout(Duration.ofSeconds(10))
                .header("Content-Type", "application/json");

        if ("GET".equalsIgnoreCase(method)) {
            return builder.GET().build();
        }

        if (body == null) {
            return builder.method(method, HttpRequest.BodyPublishers.noBody()).build();
        }

        byte[] payload = objectMapper.writeValueAsBytes(body);
        return builder.method(method, HttpRequest.BodyPublishers.ofByteArray(payload)).build();
    }

    private String encodePathSegment(String value) {
        return URLEncoder.encode(value, StandardCharsets.UTF_8).replace("+", "%20");
    }
}

package am.froshy.mialu.launcher.api.internal;

import am.froshy.mialu.launcher.application.LauncherService;
import am.froshy.mialu.launcher.application.LauncherUpdateService;
import am.froshy.mialu.launcher.application.ModpackCompatibilityMode;
import am.froshy.mialu.launcher.domain.LaunchRequest;
import am.froshy.mialu.launcher.domain.MinecraftProfile;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpServer;

import java.io.IOException;
import java.io.InputStream;
import java.net.InetSocketAddress;
import java.util.List;
import java.util.Map;
import java.util.concurrent.Executors;

public final class InternalApiServer {
    private final HttpServer server;
    private final LauncherService launcherService;
    private final LauncherUpdateService updateService;
    private final ObjectMapper objectMapper;

    public InternalApiServer(int port, LauncherService launcherService, LauncherUpdateService updateService) {
        try {
            this.server = HttpServer.create(new InetSocketAddress(port), 0);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo levantar la API interna", ex);
        }

        this.launcherService = launcherService;
        this.updateService = updateService;
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
        this.server.setExecutor(Executors.newCachedThreadPool());
        createContexts();
    }

    public void start() {
        server.start();
    }

    public void stop() {
        launcherService.shutdown();
        server.stop(0);
    }

    public int getPort() {
        return server.getAddress().getPort();
    }

    private void createContexts() {
        server.createContext("/internal/v1/health",           exchange -> withErrorHandling(exchange, this::handleHealth));
        server.createContext("/internal/v1/profiles",         exchange -> withErrorHandling(exchange, this::handleProfiles));
        server.createContext("/internal/v1/launch",           exchange -> withErrorHandling(exchange, this::handleLaunch));
        server.createContext("/internal/v1/launch-prepared",  exchange -> withErrorHandling(exchange, this::handleLaunchPrepared));
        server.createContext("/internal/v1/launch-prepared/start", exchange -> withErrorHandling(exchange, this::handleLaunchPreparedStart));
        server.createContext("/internal/v1/downloads",        exchange -> withErrorHandling(exchange, this::handleDownloads));
        server.createContext("/internal/v1/updates/check",    exchange -> withErrorHandling(exchange, this::handleUpdateCheck));
        server.createContext("/internal/v1/versions/prepare", exchange -> withErrorHandling(exchange, this::handlePrepareVersion));
        server.createContext("/internal/v1/settings/modpack-compat", exchange -> withErrorHandling(exchange, this::handleModpackCompatibility));
    }

    private void handleHealth(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, launcherService.health());
    }

    private void handleProfiles(HttpExchange exchange) throws IOException {
        String path = exchange.getRequestURI().getPath();
        String method = exchange.getRequestMethod();
        String basePath = "/internal/v1/profiles";

        if ("GET".equalsIgnoreCase(method) && basePath.equals(path)) {
            sendJson(exchange, 200, launcherService.listProfiles());
            return;
        }
        if ("POST".equalsIgnoreCase(method) && basePath.equals(path)) {
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile created = launcherService.createProfile(profile);
            sendJson(exchange, 201, created);
            return;
        }

        if ("GET".equalsIgnoreCase(method) && path.startsWith(basePath + "/") && path.endsWith("/instance-path")) {
            String profileId = path.substring((basePath + "/").length(), path.length() - "/instance-path".length());
            sendJson(exchange, 200, Map.of("instancePath", launcherService.getProfileInstancePath(profileId)));
            return;
        }

        if ("PUT".equalsIgnoreCase(method) && path.startsWith(basePath + "/")) {
            String existingId = path.substring((basePath + "/").length());
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile updated = launcherService.updateProfile(existingId, profile);
            sendJson(exchange, 200, updated);
            return;
        }

        if ("DELETE".equalsIgnoreCase(method) && path.startsWith(basePath + "/")) {
            String profileId = path.substring((basePath + "/").length());
            MinecraftProfile deleted = launcherService.deleteProfile(profileId);
            sendJson(exchange, 200, deleted);
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST", "PUT", "DELETE"));
    }

    private void handleLaunch(HttpExchange exchange) throws IOException {
        String path   = exchange.getRequestURI().getPath();
        String method = exchange.getRequestMethod();

        // POST /internal/v1/launch  → iniciar juego
        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.launch(request));
            return;
        }

        // GET /internal/v1/launch/{id}/output?from=N  → líneas de output
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/output")) {
            String id = extractSegment(path, "/output");
            int fromIndex = parseQueryInt(exchange.getRequestURI().getQuery(), "from", 0);
            sendJson(exchange, 200, launcherService.getGameOutput(id, fromIndex));
            return;
        }

        // GET /internal/v1/launch/{id}/alive  → ¿el proceso sigue vivo?
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/alive")) {
            String id = extractSegment(path, "/alive");
            sendJson(exchange, 200, Map.of("alive", launcherService.isGameAlive(id)));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private static String extractSegment(String path, String suffix) {
        String base = "/internal/v1/launch/";
        String mid  = path.substring(base.length(), path.length() - suffix.length());
        return mid;
    }

    private static int parseQueryInt(String query, String key, int defaultVal) {
        if (query == null) return defaultVal;
        for (String param : query.split("&")) {
            if (param.startsWith(key + "=")) {
                try { return Integer.parseInt(param.substring(key.length() + 1)); }
                catch (NumberFormatException ignored) {}
            }
        }
        return defaultVal;
    }

    private void handleLaunchPrepared(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String path = exchange.getRequestURI().getPath();

        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch-prepared".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.prepareAndLaunch(request));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && path.startsWith("/internal/v1/launch-prepared/")) {
            String opId = path.substring("/internal/v1/launch-prepared/".length());
            launcherService.getPreparedLaunchStatus(opId)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Operacion no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleLaunchPreparedStart(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }
        LaunchRequest request = readBody(exchange, LaunchRequest.class);
        sendJson(exchange, 202, launcherService.startPreparedLaunch(request));
    }

    private void handleDownloads(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String fullPath = exchange.getRequestURI().getPath();
        String basePath = "/internal/v1/downloads";

        if ("POST".equalsIgnoreCase(method) && basePath.equals(fullPath)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            sendJson(exchange, 202, launcherService.startDownload(request.get("target")));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && fullPath.startsWith(basePath + "/")) {
            String id = fullPath.substring((basePath + "/").length());
            launcherService.getDownloadStatus(id)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Descarga no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleUpdateCheck(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, updateService.checkForUpdates());
    }

    private void handlePrepareVersion(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }

        Map<String, String> request = readBody(exchange, new TypeReference<>() {});
        String version = request.get("version");
        sendJson(exchange, 202, launcherService.prepareVersion(version));
    }

    private void handleModpackCompatibility(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        if ("GET".equalsIgnoreCase(method)) {
            ModpackCompatibilityMode mode = launcherService.getModpackCompatibilityMode();
            sendJson(exchange, 200, Map.of(
                    "mode", mode.name(),
                    "allowedSources", switch (mode) {
                        case BOTH -> List.of("MODRINTH", "CURSEFORGE");
                        case MODRINTH_ONLY -> List.of("MODRINTH");
                        case CURSEFORGE_ONLY -> List.of("CURSEFORGE");
                    }
            ));
            return;
        }

        if ("POST".equalsIgnoreCase(method)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            String rawMode = request.get("mode");
            ModpackCompatibilityMode mode = ModpackCompatibilityMode.fromEnvironment(rawMode);
            ModpackCompatibilityMode applied = launcherService.setModpackCompatibilityMode(mode);
            sendJson(exchange, 200, Map.of("mode", applied.name()));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST"));
    }

    private <T> T readBody(HttpExchange exchange, Class<T> type) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, type);
        }
    }

    private <T> T readBody(HttpExchange exchange, TypeReference<T> typeReference) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, typeReference);
        }
    }

    private void withErrorHandling(HttpExchange exchange, ExchangeHandler handler) throws IOException {
        try {
            handler.handle(exchange);
        } catch (IllegalArgumentException ex) {
            sendJson(exchange, 400, Map.of("error", ex.getMessage()));
        } catch (Exception ex) {
            sendJson(exchange, 500, Map.of("error", "Error interno", "detail", ex.getMessage()));
        } finally {
            exchange.close();
        }
    }

    private void sendMethodNotAllowed(HttpExchange exchange, List<String> allowedMethods) throws IOException {
        exchange.getResponseHeaders().set("Allow", String.join(", ", allowedMethods));
        sendJson(exchange, 405, Map.of("error", "Metodo no permitido"));
    }

    private void sendJson(HttpExchange exchange, int statusCode, Object body) throws IOException {
        byte[] payload = objectMapper.writerWithDefaultPrettyPrinter().writeValueAsBytes(body);
        exchange.getResponseHeaders().set("Content-Type", "application/json; charset=utf-8");
        exchange.sendResponseHeaders(statusCode, payload.length);
        exchange.getResponseBody().write(payload);
    }

    private void sendJsonUnchecked(HttpExchange exchange, int statusCode, Object body) {
        try {
            sendJson(exchange, statusCode, body);
        } catch (IOException ex) {
            throw new IllegalStateException(ex);
        }
    }

    @FunctionalInterface
    private interface ExchangeHandler {
        void handle(HttpExchange exchange) throws IOException;
    }
}

package am.froshy.mialu.launcher.api.internal;

import am.froshy.mialu.launcher.application.LauncherService;
import am.froshy.mialu.launcher.application.LauncherUpdateService;
import am.froshy.mialu.launcher.application.ModpackCompatibilityMode;
import am.froshy.mialu.launcher.domain.LaunchRequest;
import am.froshy.mialu.launcher.domain.MinecraftProfile;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpServer;

import java.io.IOException;
import java.io.InputStream;
import java.net.InetSocketAddress;
import java.net.URLDecoder;
import java.nio.charset.StandardCharsets;
import java.util.Locale;
import java.util.List;
import java.util.Map;
import java.util.concurrent.Executors;

public final class InternalApiServer {
    private final HttpServer server;
    private final LauncherService launcherService;
    private final LauncherUpdateService updateService;
    private final ObjectMapper objectMapper;

    public InternalApiServer(int port, LauncherService launcherService, LauncherUpdateService updateService) {
        try {
            this.server = HttpServer.create(new InetSocketAddress(port), 0);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo levantar la API interna", ex);
        }

        this.launcherService = launcherService;
        this.updateService = updateService;
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
        this.server.setExecutor(Executors.newCachedThreadPool());
        createContexts();
    }

    public void start() {
        server.start();
    }

    public void stop() {
        launcherService.shutdown();
        server.stop(0);
    }

    public int getPort() {
        return server.getAddress().getPort();
    }

    private void createContexts() {
        server.createContext("/internal/v1/health",           exchange -> withErrorHandling(exchange, this::handleHealth));
        server.createContext("/internal/v1/profiles",         exchange -> withErrorHandling(exchange, this::handleProfiles));
        server.createContext("/internal/v1/launch",           exchange -> withErrorHandling(exchange, this::handleLaunch));
        server.createContext("/internal/v1/launch-prepared",  exchange -> withErrorHandling(exchange, this::handleLaunchPrepared));
        server.createContext("/internal/v1/launch-prepared/start", exchange -> withErrorHandling(exchange, this::handleLaunchPreparedStart));
        server.createContext("/internal/v1/downloads",        exchange -> withErrorHandling(exchange, this::handleDownloads));
        server.createContext("/internal/v1/updates/check",    exchange -> withErrorHandling(exchange, this::handleUpdateCheck));
        server.createContext("/internal/v1/versions/prepare", exchange -> withErrorHandling(exchange, this::handlePrepareVersion));
        server.createContext("/internal/v1/settings/modpack-compat", exchange -> withErrorHandling(exchange, this::handleModpackCompatibility));
    }

    private void handleHealth(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, launcherService.health());
    }

    private void handleProfiles(HttpExchange exchange) throws IOException {
        String path = exchange.getRequestURI().getRawPath();
        String method = exchange.getRequestMethod();
        String basePath = "/internal/v1/profiles";

        if ("GET".equalsIgnoreCase(method) && basePath.equals(path)) {
            sendJson(exchange, 200, launcherService.listProfiles());
            return;
        }
        if ("POST".equalsIgnoreCase(method) && basePath.equals(path)) {
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile created = launcherService.createProfile(profile);
            sendJson(exchange, 201, created);
            return;
        }

        if ("GET".equalsIgnoreCase(method) && path.startsWith(basePath + "/") && path.endsWith("/instance-path")) {
            String profileId = decodeUrlComponent(path.substring((basePath + "/").length(), path.length() - "/instance-path".length()));
            sendJson(exchange, 200, Map.of("instancePath", launcherService.getProfileInstancePath(profileId)));
            return;
        }

        if ("PUT".equalsIgnoreCase(method) && path.startsWith(basePath + "/")) {
            String existingId = decodeUrlComponent(path.substring((basePath + "/").length()));
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile updated = launcherService.updateProfile(existingId, profile);
            sendJson(exchange, 200, updated);
            return;
        }

        if ("DELETE".equalsIgnoreCase(method) && path.startsWith(basePath + "/")) {
            String profileId = decodeUrlComponent(path.substring((basePath + "/").length()));
            MinecraftProfile deleted = launcherService.deleteProfile(profileId);
            sendJson(exchange, 200, deleted);
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST", "PUT", "DELETE"));
    }

    private void handleLaunch(HttpExchange exchange) throws IOException {
        String path   = exchange.getRequestURI().getRawPath();
        String method = exchange.getRequestMethod();

        // POST /internal/v1/launch  → iniciar juego
        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.launch(request));
            return;
        }

        // GET /internal/v1/launch/{id}/output?from=N  → líneas de output
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/output")) {
            String id = extractSegment(path, "/output");
            int fromIndex = parseQueryInt(exchange.getRequestURI().getRawQuery(), "from", 0);
            sendJson(exchange, 200, launcherService.getGameOutput(id, fromIndex));
            return;
        }

        // GET /internal/v1/launch/{id}/alive  → ¿el proceso sigue vivo?
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/alive")) {
            String id = extractSegment(path, "/alive");
            sendJson(exchange, 200, Map.of("alive", launcherService.isGameAlive(id)));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private static String extractSegment(String path, String suffix) {
        String base = "/internal/v1/launch/";
        return decodeUrlComponent(path.substring(base.length(), path.length() - suffix.length()));
    }

    private static int parseQueryInt(String query, String key, int defaultVal) {
        if (query == null) return defaultVal;
        for (String param : query.split("&")) {
            if (param.startsWith(key + "=")) {
                try { return Integer.parseInt(decodeUrlComponent(param.substring(key.length() + 1))); }
                catch (NumberFormatException ignored) {}
            }
        }
        return defaultVal;
    }

    private static String parseQueryString(String query, String key, String defaultVal) {
        if (query == null || query.isBlank()) return defaultVal;
        for (String param : query.split("&")) {
            if (param.startsWith(key + "=")) {
                String value = decodeUrlComponent(param.substring(key.length() + 1));
                return value.isBlank() ? defaultVal : value;
            }
        }
        return defaultVal;
    }

    private void handleLaunchPrepared(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String path = exchange.getRequestURI().getRawPath();

        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch-prepared".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.prepareAndLaunch(request));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && path.startsWith("/internal/v1/launch-prepared/")) {
            String opId = decodeUrlComponent(path.substring("/internal/v1/launch-prepared/".length()));
            launcherService.getPreparedLaunchStatus(opId)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Operacion no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleLaunchPreparedStart(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }
        LaunchRequest request = readBody(exchange, LaunchRequest.class);
        sendJson(exchange, 202, launcherService.startPreparedLaunch(request));
    }

    private void handleDownloads(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String fullPath = exchange.getRequestURI().getRawPath();
        String basePath = "/internal/v1/downloads";

        if ("POST".equalsIgnoreCase(method) && basePath.equals(fullPath)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            sendJson(exchange, 202, launcherService.startDownload(request.get("target")));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && fullPath.startsWith(basePath + "/")) {
            String id = decodeUrlComponent(fullPath.substring((basePath + "/").length()));
            launcherService.getDownloadStatus(id)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Descarga no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleUpdateCheck(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        String trigger = parseQueryString(exchange.getRequestURI().getQuery(), "trigger", "MANUAL");
        boolean manual = !"WEEKLY".equalsIgnoreCase(trigger.toUpperCase(Locale.ROOT));
        sendJson(exchange, 200, updateService.checkForUpdates(manual));
    }

    private void handlePrepareVersion(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }

        Map<String, String> request = readBody(exchange, new TypeReference<>() {});
        String version = request.get("version");
        sendJson(exchange, 202, launcherService.prepareVersion(version));
    }

    private void handleModpackCompatibility(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        if ("GET".equalsIgnoreCase(method)) {
            ModpackCompatibilityMode mode = launcherService.getModpackCompatibilityMode();
            sendJson(exchange, 200, Map.of(
                    "mode", mode.name(),
                    "allowedSources", switch (mode) {
                        case BOTH -> List.of("MODRINTH", "CURSEFORGE");
                        case MODRINTH_ONLY -> List.of("MODRINTH");
                        case CURSEFORGE_ONLY -> List.of("CURSEFORGE");
                    }
            ));
            return;
        }

        if ("POST".equalsIgnoreCase(method)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            String rawMode = request.get("mode");
            ModpackCompatibilityMode mode = ModpackCompatibilityMode.fromEnvironment(rawMode);
            ModpackCompatibilityMode applied = launcherService.setModpackCompatibilityMode(mode);
            sendJson(exchange, 200, Map.of("mode", applied.name()));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST"));
    }

    private static String decodeUrlComponent(String value) {
        return URLDecoder.decode(value, StandardCharsets.UTF_8);
    }

    private <T> T readBody(HttpExchange exchange, Class<T> type) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, type);
        }
    }

    private <T> T readBody(HttpExchange exchange, TypeReference<T> typeReference) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, typeReference);
        }
    }

    private void withErrorHandling(HttpExchange exchange, ExchangeHandler handler) throws IOException {
        try {
            handler.handle(exchange);
        } catch (IllegalArgumentException ex) {
            sendJson(exchange, 400, Map.of("error", ex.getMessage()));
        } catch (Exception ex) {
            sendJson(exchange, 500, Map.of("error", "Error interno", "detail", ex.getMessage()));
        } finally {
            exchange.close();
        }
    }

    private void sendMethodNotAllowed(HttpExchange exchange, List<String> allowedMethods) throws IOException {
        exchange.getResponseHeaders().set("Allow", String.join(", ", allowedMethods));
        sendJson(exchange, 405, Map.of("error", "Metodo no permitido"));
    }

    private void sendJson(HttpExchange exchange, int statusCode, Object body) throws IOException {
        byte[] payload = objectMapper.writerWithDefaultPrettyPrinter().writeValueAsBytes(body);
        exchange.getResponseHeaders().set("Content-Type", "application/json; charset=utf-8");
        exchange.sendResponseHeaders(statusCode, payload.length);
        exchange.getResponseBody().write(payload);
    }

    private void sendJsonUnchecked(HttpExchange exchange, int statusCode, Object body) {
        try {
            sendJson(exchange, statusCode, body);
        } catch (IOException ex) {
            throw new IllegalStateException(ex);
        }
    }

    @FunctionalInterface
    private interface ExchangeHandler {
        void handle(HttpExchange exchange) throws IOException;
    }
}

package am.froshy.mialu.launcher.application;

import am.froshy.mialu.launcher.domain.LauncherUpdateStatus;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.Map;

public final class LauncherUpdateService {
    private final String currentVersion;
    private final String metadataUrl;
    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;

    public LauncherUpdateService(String currentVersion, String metadataUrl) {
        this.currentVersion = currentVersion;
        this.metadataUrl = metadataUrl;
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(3))
                .build();
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
    }

    public LauncherUpdateStatus checkForUpdates() {
        if (metadataUrl == null || metadataUrl.isBlank()) {
            return new LauncherUpdateStatus("NO_CONFIG", currentVersion, currentVersion, "", "Configura MIALU_UPDATE_METADATA_URL");
        }

        try {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(metadataUrl))
                    .timeout(Duration.ofSeconds(5))
                    .GET()
                    .build();

            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() >= 400) {
                return new LauncherUpdateStatus("CHECK_FAILED", currentVersion, currentVersion, "", "HTTP " + response.statusCode());
            }

            Map<String, String> metadata = objectMapper.readValue(response.body(), new TypeReference<>() {});
            String latestVersion = metadata.getOrDefault("version", currentVersion);
            String downloadUrl = metadata.getOrDefault("downloadUrl", "");
            String notes = metadata.getOrDefault("notes", "Sin notas");

            if (!currentVersion.equalsIgnoreCase(latestVersion)) {
                return new LauncherUpdateStatus("UPDATE_AVAILABLE", currentVersion, latestVersion, downloadUrl, notes);
            }
            return new LauncherUpdateStatus("UP_TO_DATE", currentVersion, latestVersion, downloadUrl, notes);
        } catch (Exception ex) {
            return new LauncherUpdateStatus("CHECK_FAILED", currentVersion, currentVersion, "", ex.getMessage());
        }
    }
}

package am.froshy.mialu.launcher.application;

import am.froshy.mialu.launcher.config.LauncherSettings;
import am.froshy.mialu.launcher.domain.LauncherUpdateStatus;
import am.froshy.mialu.launcher.infrastructure.SettingsStore;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardCopyOption;
import java.nio.file.StandardOpenOption;
import java.time.Duration;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Locale;

public final class LauncherUpdateService {
    private static final String DEFAULT_RELEASE_API_URL = "https://api.github.com/repos/FroshGames/launcher_froshy/releases/latest";
    private static final String USER_AGENT = "Launcher_Mialu-Updater/1.0";

    private final String currentVersion;
    private final String releaseApiUrl;
    private final Path updatesDirectory;
    private final SettingsStore settingsStore;
    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;

    public LauncherUpdateService(String currentVersion, String metadataUrl) {
        this(currentVersion, metadataUrl,
                Path.of(System.getProperty("java.io.tmpdir"), "launcher-mialu-updates"),
                new SettingsStore(
                        Path.of(System.getProperty("java.io.tmpdir"), "launcher-mialu-settings.json"),
                        new ObjectMapper().findAndRegisterModules()
                ));
    }

    public LauncherUpdateService(String currentVersion, String releaseApiUrl, Path updatesDirectory, SettingsStore settingsStore) {
        this.currentVersion = currentVersion;
        this.releaseApiUrl = releaseApiUrl == null || releaseApiUrl.isBlank() ? DEFAULT_RELEASE_API_URL : releaseApiUrl;
        this.updatesDirectory = updatesDirectory;
        this.settingsStore = settingsStore;
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(3))
                .build();
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
    }

    public LauncherUpdateStatus checkForUpdates() {
        return checkForUpdates(true);
    }

    public LauncherUpdateStatus checkForUpdates(boolean manualTrigger) {
        LauncherSettings settings = settingsStore.load();
        if (!manualTrigger && !shouldRunWeeklyCheck(settings.lastUpdateCheckAt())) {
            return new LauncherUpdateStatus(
                    "SKIPPED",
                    currentVersion,
                    safe(settings.lastDownloadedVersion(), currentVersion),
                    "",
                    "La comprobación automática semanal aún no toca.",
                    formatInstant(settings.lastUpdateCheckAt()),
                    safe(settings.lastDownloadedAssetName(), ""),
                    safe(settings.lastDownloadedFile(), "")
            );
        }

        Instant checkedAt = Instant.now();
        settings = settings.withLastUpdateCheckAt(checkedAt);
        settingsStore.save(settings);

        try {
            JsonNode release = getJson(URI.create(releaseApiUrl));
            String latestVersion = normalizeVersion(extractLatestVersion(release));
            String normalizedCurrent = normalizeVersion(currentVersion);
            String notes = release.path("body").asText("Sin notas");
            ReleaseAsset asset = selectBestAsset(release.path("assets"));

            if (compareVersions(normalizedCurrent, latestVersion) >= 0) {
                return new LauncherUpdateStatus(
                        "UP_TO_DATE",
                        currentVersion,
                        latestVersion,
                        asset == null ? "" : asset.downloadUrl(),
                        notes,
                        formatInstant(checkedAt),
                        safe(settings.lastDownloadedAssetName(), ""),
                        safe(settings.lastDownloadedFile(), "")
                );
            }

            if (asset == null) {
                return new LauncherUpdateStatus(
                        "UPDATE_AVAILABLE",
                        currentVersion,
                        latestVersion,
                        "",
                        "Hay una release nueva, pero no se encontró un package descargable compatible.",
                        formatInstant(checkedAt),
                        safe(settings.lastDownloadedAssetName(), ""),
                        safe(settings.lastDownloadedFile(), "")
                );
            }

            Path downloaded = downloadAssetIfNeeded(asset, latestVersion);
            LauncherSettings updatedSettings = settings
                    .withLastUpdateCheckAt(checkedAt)
                    .withDownloadedUpdate(latestVersion, asset.name(), downloaded.toAbsolutePath().toString());
            settingsStore.save(updatedSettings);

            return new LauncherUpdateStatus(
                    "UPDATE_DOWNLOADED",
                    currentVersion,
                    latestVersion,
                    asset.downloadUrl(),
                    notes,
                    formatInstant(checkedAt),
                    asset.name(),
                    downloaded.toAbsolutePath().toString()
            );
        } catch (Exception ex) {
            return new LauncherUpdateStatus(
                    "CHECK_FAILED",
                    currentVersion,
                    currentVersion,
                    "",
                    ex.getMessage(),
                    formatInstant(checkedAt),
                    safe(settings.lastDownloadedAssetName(), ""),
                    safe(settings.lastDownloadedFile(), "")
            );
        }
    }

    private boolean shouldRunWeeklyCheck(Instant lastCheckAt) {
        if (lastCheckAt == null) {
            return true;
        }
        return lastCheckAt.plus(7, ChronoUnit.DAYS).isBefore(Instant.now());
    }

    private JsonNode getJson(URI uri) throws IOException, InterruptedException {
        HttpRequest request = HttpRequest.newBuilder()
                    .uri(uri)
                    .timeout(Duration.ofSeconds(5))
                    .header("User-Agent", USER_AGENT)
                    .GET()
                    .build();
        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
        if (response.statusCode() >= 400) {
            throw new IOException("HTTP " + response.statusCode() + " al consultar updates");
        }
        return objectMapper.readTree(response.body());
    }

    private String extractLatestVersion(JsonNode release) {
        String tag = release.path("tag_name").asText("").trim();
        if (!tag.isBlank()) return tag;
        String name = release.path("name").asText("").trim();
        if (!name.isBlank()) return name;
        return currentVersion;
    }

    private ReleaseAsset selectBestAsset(JsonNode assetsNode) {
        if (assetsNode == null || !assetsNode.isArray() || assetsNode.isEmpty()) {
            return null;
        }
        List<ReleaseAsset> assets = new ArrayList<>();
        for (JsonNode assetNode : assetsNode) {
            String name = assetNode.path("name").asText("");
            String downloadUrl = assetNode.path("browser_download_url").asText("");
            if (name.isBlank() || downloadUrl.isBlank()) continue;
            assets.add(new ReleaseAsset(name, downloadUrl));
        }
        if (assets.isEmpty()) return null;

        String os = System.getProperty("os.name", "").toLowerCase(Locale.ROOT);
        return assets.stream()
                .sorted(Comparator.comparingInt(asset -> assetPriority(asset, os)))
                .findFirst()
                .orElse(null);
    }

    private int assetPriority(ReleaseAsset asset, String os) {
        String name = asset.name().toLowerCase(Locale.ROOT);
        if (os.contains("win")) {
            if (name.contains("launcher_mialu") && name.endsWith("win64.zip")) return 0;
            if (name.endsWith(".zip")) return 1;
        } else if (os.contains("mac") || os.contains("nix") || os.contains("nux")) {
            if (name.contains("launcher_mialu") && name.endsWith(".tar.gz")) return 0;
            if (name.endsWith(".tar.gz")) return 1;
        }
        if (name.contains("launcher_mialu") && name.endsWith(".jar")) return 2;
        if (name.endsWith(".jar")) return 3;
        return 10;
    }

    private Path downloadAssetIfNeeded(ReleaseAsset asset, String latestVersion) throws IOException, InterruptedException {
        Files.createDirectories(updatesDirectory);
        String safeVersion = latestVersion.replaceAll("[^A-Za-z0-9._-]", "_");
        Path destination = updatesDirectory.resolve(safeVersion + "-" + asset.name());
        if (Files.exists(destination) && Files.size(destination) > 0) {
            return destination;
        }

        Path tmp = destination.resolveSibling(destination.getFileName() + ".part");
        HttpRequest request = HttpRequest.newBuilder(URI.create(asset.downloadUrl()))
                .timeout(Duration.ofMinutes(10))
                .header("User-Agent", USER_AGENT)
                .GET()
                .build();
        HttpResponse<InputStream> response = httpClient.send(request, HttpResponse.BodyHandlers.ofInputStream());
        if (response.statusCode() >= 400) {
            throw new IOException("HTTP " + response.statusCode() + " al descargar " + asset.name());
        }
        try (InputStream in = response.body();
             OutputStream out = Files.newOutputStream(tmp, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING)) {
            in.transferTo(out);
        }
        Files.move(tmp, destination, StandardCopyOption.REPLACE_EXISTING);
        return destination;
    }

    private String normalizeVersion(String version) {
        if (version == null || version.isBlank()) return "0";
        return version.trim().replaceFirst("^[Vv]", "");
    }

    private int compareVersions(String current, String latest) {
        String[] left = current.replace("-SNAPSHOT", ".-1").split("[._-]");
        String[] right = latest.replace("-SNAPSHOT", ".-1").split("[._-]");
        int len = Math.max(left.length, right.length);
        for (int i = 0; i < len; i++) {
            String a = i < left.length ? left[i] : "0";
            String b = i < right.length ? right[i] : "0";
            int cmp;
            if (a.matches("-?\\d+") && b.matches("-?\\d+")) {
                cmp = Integer.compare(Integer.parseInt(a), Integer.parseInt(b));
            } else {
                cmp = a.compareToIgnoreCase(b);
            }
            if (cmp != 0) {
                return cmp;
            }
        }
        return 0;
    }

    private String formatInstant(Instant instant) {
        return instant == null ? "" : instant.toString();
    }

    private String safe(String value, String fallback) {
        return value == null || value.isBlank() ? fallback : value;
    }

    private record ReleaseAsset(String name, String downloadUrl) {}
}

package am.froshy.mialu.launcher.config;

/**
 * Configuración persisitida del launcher (modo rendimiento, intervalos de polling, etc.).
 */
public record LauncherSettings(
        boolean performanceMode,
        int consolePollIntervalMs,
        int launchPollIntervalMs,
        int progressThresholdPct
) {
    public LauncherSettings {
        if (consolePollIntervalMs <= 0) consolePollIntervalMs = 600;
        if (launchPollIntervalMs  <= 0) launchPollIntervalMs  = 300;
        if (progressThresholdPct  <= 0) progressThresholdPct  = 1;
    }

    public static LauncherSettings defaults() {
        return new LauncherSettings(false, 600, 300, 1);
    }

    public LauncherSettings withPerformanceMode(boolean perf) {
        return new LauncherSettings(perf, perf ? 1200 : 600, perf ? 600 : 300, perf ? 3 : 1);
    }
}

package am.froshy.mialu.launcher.config;

import java.time.Instant;

/**
 * Configuración persisitida del launcher (modo rendimiento, intervalos de polling, etc.).
 */
public record LauncherSettings(
        boolean performanceMode,
        int consolePollIntervalMs,
        int launchPollIntervalMs,
        int progressThresholdPct,
        Instant lastUpdateCheckAt,
        String lastDownloadedVersion,
        String lastDownloadedAssetName,
        String lastDownloadedFile
) {
    public LauncherSettings {
        if (consolePollIntervalMs <= 0) consolePollIntervalMs = 600;
        if (launchPollIntervalMs  <= 0) launchPollIntervalMs  = 300;
        if (progressThresholdPct  <= 0) progressThresholdPct  = 1;
    }

    public static LauncherSettings defaults() {
        return new LauncherSettings(false, 600, 300, 1, null, "", "", "");
    }

    public LauncherSettings withPerformanceMode(boolean perf) {
        return new LauncherSettings(
                perf,
                perf ? 1200 : 600,
                perf ? 600 : 300,
                perf ? 3 : 1,
                lastUpdateCheckAt,
                lastDownloadedVersion,
                lastDownloadedAssetName,
                lastDownloadedFile
        );
    }

    public LauncherSettings withLastUpdateCheckAt(Instant checkedAt) {
        return new LauncherSettings(
                performanceMode,
                consolePollIntervalMs,
                launchPollIntervalMs,
                progressThresholdPct,
                checkedAt,
                lastDownloadedVersion,
                lastDownloadedAssetName,
                lastDownloadedFile
        );
    }

    public LauncherSettings withDownloadedUpdate(String version, String assetName, String file) {
        return new LauncherSettings(
                performanceMode,
                consolePollIntervalMs,
                launchPollIntervalMs,
                progressThresholdPct,
                lastUpdateCheckAt,
                version == null ? "" : version,
                assetName == null ? "" : assetName,
                file == null ? "" : file
        );
    }
}

